<script lang="ts">
  import { groupSelectOptions } from '@fex/components-core/select/filter-options'; import { getSelectVirtualRange } from '@fex/components-core/select/virtual'; import type { SelectOption } from '@fex/components-core/select/types'; import { selectEmptyClassName,selectGroupLabelClassName,selectListClassName,selectLoadingClassName,selectOptionClassName,selectOptionIndicatorClassName,selectOptionLabelClassName } from '@fex/components-styles/select'; import { cn } from '@fex/utils'; import type { Snippet } from 'svelte'; import { getContext } from 'svelte'; import CheckIcon from '../../icon/check.svelte'; import { selectContextKey,type SelectContext } from './context'
  let{class:className,emptyText='No options',loadingText='Loading...',option}:{class?:string;emptyText?:string;loadingText?:string;option?:Snippet<[SelectOption,{selected:boolean;active:boolean;disabled:boolean}]>}=$props();const select=getContext<SelectContext>(selectContextKey);const snapshot=select.snapshot;let viewport=$state({scrollTop:0,height:320});const range=$derived(select.virtual()?getSelectVirtualRange(select.visibleOptions().length,viewport.scrollTop,viewport.height,select.virtual()!):undefined);const groups=$derived(groupSelectOptions(select.visibleOptions()));const selected=(item:SelectOption)=>select.controller.selection.isSelected(item.value);const disabled=(item:SelectOption)=>item.disabled===true||select.controller.selection.isDisabled(item.value)
</script>
<div id={select.listId} role="listbox" aria-multiselectable={select.multiple()||undefined} class={cn(selectListClassName,className)} onscroll={event=>viewport={scrollTop:event.currentTarget.scrollTop,height:event.currentTarget.clientHeight}}>
  {#if select.loading()}<div class={selectLoadingClassName}>{loadingText}</div>
  {:else if !select.visibleOptions().length}<div class={selectEmptyClassName}>{emptyText}</div>
  {:else if range}<div style:height={`${range.totalSize}px`} style:position="relative"><div style:position="absolute" style:inset-inline="0" style:top={`${range.offset}px`}>{#each select.visibleOptions().slice(range.start,range.end) as item (item.value)}{@render row(item)}{/each}</div></div>
  {:else}{#each groups as group (group.label??'')}{#if group.label}<div class={selectGroupLabelClassName}>{group.label}</div>{/if}{#each group.options as item (item.value)}{@render row(item)}{/each}{/each}
  {/if}
</div>
{#snippet row(item:SelectOption)}{@const state={selected:selected(item),active:$snapshot.activeValue===item.value,disabled:disabled(item)}}<div id={`${select.listId}-${item.value}`} role="option" tabindex="-1" aria-selected={state.selected} aria-disabled={state.disabled||undefined} data-selected={state.selected||undefined} data-active={state.active||undefined} data-disabled={state.disabled||undefined} class={selectOptionClassName} onpointermove={()=>select.controller.setActiveValue(item.value,'pointer')} onpointerdown={event=>event.preventDefault()} onclick={()=>!state.disabled&&select.controller.selectValue(item.value)} onkeydown={event=>{if((event.key==='Enter'||event.key===' ')&&!state.disabled){event.preventDefault();select.controller.selectValue(item.value)}}}><span class={selectOptionLabelClassName}>{#if option}{@render option(item,state)}{:else}{item.label}{/if}</span><span class={selectOptionIndicatorClassName}><CheckIcon/></span></div>{/snippet}
